const body = $input.first().json.body || $input.first().json;
const profile_id = body.profile_id;
const analysis_type = body.analysis_type || 'performance';

if (!profile_id) throw new Error('Missing required field: profile_id');

// Basic UUID format check
if (!/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(profile_id)) {
  throw new Error('profile_id must be a valid UUID');
}

return [{ json: { profile_id, analysis_type } }];

// Aggregate all post items into one item with a posts array
const allItems = $input.all();
const profile_id = $('Validate Input').first().json.profile_id;
const analysis_type = $('Validate Input').first().json.analysis_type;

if (allItems.length === 0) {
  throw new Error(`No posts found for profile_id: ${profile_id}. Run the scrape pipeline first.`);
}

const posts = allItems.map(item => item.json);
console.log(`Aggregated ${posts.length} posts for analysis`);

return [{ json: { profile_id, analysis_type, posts } }];

// Build a structured prompt for Claude with all post data
const profileResp = $input.first().json;
const profile = Array.isArray(profileResp) ? profileResp[0] : profileResp;

if (!profile?.id) {
  throw new Error('Profile not found in Supabase for id: ' + $('Aggregate Posts').first().json.profile_id);
}

const { posts, analysis_type } = $('Aggregate Posts').first().json;
const username = profile.username;
const followers = profile.followers;

// Format posts as a readable table for Claude
const postsTable = posts.map((p, i) => {
  const date = p.posted_at ? p.posted_at.slice(0, 10) : 'unknown';
  const caption_snippet = (p.caption || '').replace(/\n/g, ' ').slice(0, 80);
  return `${String(i+1).padStart(2)}. [${(p.content_type || 'unknown').padEnd(9)}] ${date} | ` +
         `Likes: ${String(p.likes || 0).padStart(6)} | Comments: ${String(p.comments || 0).padStart(4)} | ` +
         `Views: ${String(p.views || 0).padStart(7)} | ID: ${p.platform_post_id} | "${caption_snippet}"...`;
}).join('\n');

const systemPrompt = `You are an expert social media growth analyst specialising in Instagram content strategy. 
You analyse post performance data and provide data-driven, actionable recommendations.
You always respond with valid JSON only — no markdown, no code blocks, no explanation outside the JSON.`;

const userPrompt = `Analyse the Instagram account @${username}${followers ? ` (${followers.toLocaleString()} followers)` : ''} based on the following post data.

POSTS (${posts.length} most recent, newest first):
${postsTable}

Provide a complete performance analysis. Return ONLY a valid JSON object with exactly this structure — no markdown, no code fences:

{
  "engagement_summary": {
    "avg_likes": <number>,
    "avg_comments": <number>,
    "avg_views": <number>,
    "total_posts_analyzed": <number>,
    "top_content_type": "<string>",
    "trend": "growing" | "stable" | "declining",
    "trend_reasoning": "<1-2 sentence explanation>"
  },
  "top_posts": [
    {
      "platform_post_id": "<string>",
      "content_type": "<string>",
      "likes": <number>,
      "comments": <number>,
      "views": <number>,
      "posted_at": "<YYYY-MM-DD>",
      "why_it_worked": "<1 sentence>"
    }
  ],
  "worst_posts": [
    {
      "platform_post_id": "<string>",
      "content_type": "<string>",
      "likes": <number>,
      "views": <number>,
      "posted_at": "<YYYY-MM-DD>",
      "why_it_underperformed": "<1 sentence>"
    }
  ],
  "best_posting_times": {
    "days_of_week": ["<day>"],
    "hours_utc": [<0-23>],
    "reasoning": "<1-2 sentences based on the data>"
  },
  "content_type_breakdown": {
    "<type>": {
      "count": <number>,
      "avg_likes": <number>,
      "avg_views": <number>,
      "performance_note": "<1 sentence>"
    }
  },
  "recommendations": [
    {
      "category": "content" | "timing" | "engagement" | "hashtags" | "growth",
      "title": "<short title>",
      "description": "<2-3 sentence actionable description>",
      "priority": "high" | "medium" | "low"
    }
  ]
}

Rules:
- top_posts: pick the 3 best performing posts by combined likes+views
- worst_posts: pick the 3 lowest performing posts
- recommendations: provide exactly 5 recommendations
- All numbers must be actual numbers (not strings)
- Respond with ONLY the JSON object`;

return [{
  json: {
    profile_id: profile.id,
    profile_username: username,
    analysis_type,
    posts_count: posts.length,
    system_prompt: systemPrompt,
    user_prompt: userPrompt
  }
}];

// Extract and parse Claude's JSON response
const resp = $input.first().json;

// Claude response structure: { content: [{ type: 'text', text: '...' }] }
const rawText = resp?.content?.[0]?.text;
if (!rawText) {
  throw new Error('Claude returned no content. Full response: ' + JSON.stringify(resp));
}

// Strip any accidental markdown code fences Claude might add
const cleaned = rawText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

let analysis;
try {
  analysis = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Failed to parse Claude JSON: ' + e.message + '\n\nRaw text: ' + cleaned.slice(0, 500));
}

// Validate expected top-level keys
const required = ['engagement_summary', 'top_posts', 'worst_posts', 'best_posting_times', 'content_type_breakdown', 'recommendations'];
const missing = required.filter(k => !analysis[k]);
if (missing.length > 0) {
  throw new Error(`Claude response missing required keys: ${missing.join(', ')}`);
}

const upstream = $('Build Prompt').first().json;

return [{
  json: {
    profile_id: upstream.profile_id,
    analysis_type: upstream.analysis_type,
    raw_response: rawText,
    engagement_summary: analysis.engagement_summary,
    top_posts: analysis.top_posts,
    worst_posts: analysis.worst_posts,
    best_posting_times: analysis.best_posting_times,
    content_type_breakdown: analysis.content_type_breakdown,
    recommendations: analysis.recommendations
  }
}];

// Get the saved analysis ID from Supabase response
const analysisResp = $input.first().json;
const analysisArr = Array.isArray(analysisResp) ? analysisResp : [analysisResp];
const analysis_id = analysisArr[0]?.id;

if (!analysis_id) {
  throw new Error('Save Analysis did not return an ID: ' + JSON.stringify(analysisResp));
}

const upstream = $('Parse Claude Response').first().json;
const recs = upstream.recommendations || [];

if (recs.length === 0) {
  throw new Error('No recommendations in Claude response');
}

// Map to recommendations table schema
const rows = recs.map(r => ({
  profile_id: upstream.profile_id,
  analysis_id,
  category: ['content','timing','engagement','hashtags','growth'].includes(r.category) ? r.category : 'content',
  title: r.title || 'Recommendation',
  description: r.description || '',
  priority: ['high','medium','low'].includes(r.priority) ? r.priority : 'medium'
}));

return [{ json: { analysis_id, profile_id: upstream.profile_id, recommendations: rows } }];
